<?php
declare(strict_types=1);require dirname(__DIR__,3).'/bootstrap.php';require VP3_ROOT.'/includes/api.php';$input=vp3_api_bootstrap(['GET']);vp3_api_required($input,['product_id','timestamp','nonce']);vp3_api_execute(function()use($input){$s=vp3_db()->prepare("SELECT p.product_id,p.name,r.version,r.release_channel,r.release_notes,r.minimum_php_version,r.minimum_database_version,r.published_at FROM products p JOIN product_releases r ON r.product_id=p.id WHERE p.product_id=? AND p.status='active' AND r.status='published' ORDER BY r.published_at DESC,r.id DESC LIMIT 1");$s->execute([(string)$input['product_id']]);$r=$s->fetch();if(!is_array($r))throw new RuntimeException('release_not_found');return $r;});
